cssRequirements.css:
@layer priority1 {
  .basex-collapsible-panel {
    height: var(--collapsible-panel-height);
    overflow: hidden;
    transition: height 200ms cubic-bezier(0.4, 0, 0.2, 1);
  }
  .basex-collapsible-panel[data-starting-style],
  .basex-collapsible-panel[data-ending-style] {
    height: 0;
  }
}
